// Lightweight loader to avoid external CDNs.
// Loads vis-network ESM from the extension's local node_modules and wires basic interactions.
(async function () {
  const visUri = window.__VIS_ESM_URI__;
  if (!visUri) {
    console.error("PRISM_VIZ: missing __VIS_ESM_URI__");
    return;
  }

  const vscode = acquireVsCodeApi();
  const { DataSet, Network } = await import(visUri);

  const container = document.getElementById("graph");
  const searchEl = document.getElementById("search");
  const statusEl = document.getElementById("status");

  const nodes = new DataSet();
  const edges = new DataSet();

  const network = new Network(
    container,
    { nodes, edges },
    {
      layout: { improvedLayout: true },
      physics: {
        enabled: true,
        solver: "forceAtlas2Based",
        forceAtlas2Based: {
          gravitationalConstant: -40,
          centralGravity: 0.01,
          springLength: 140,
          springConstant: 0.06,
        },
        stabilization: { iterations: 200 },
      },
      interaction: { hover: true, navigationButtons: true, keyboard: true },
      nodes: {
        shape: "dot",
        size: 10,
        font: { color: "#e5e7eb", size: 12 },
        color: {
          background: "#60a5fa",
          border: "rgba(96,165,250,0.5)",
          highlight: { background: "#a78bfa", border: "#a78bfa" },
        },
      },
      edges: {
        arrows: { to: { enabled: true, scaleFactor: 0.6 } },
        color: { color: "rgba(148,163,184,0.35)", highlight: "#fb7185" },
        smooth: { type: "dynamic" },
      },
    }
  );

  function setStatus(text) {
    if (statusEl) statusEl.textContent = text;
  }

  function setGraph(graph, opts) {
    nodes.clear();
    edges.clear();

    const nodeItems = graph.nodes.map((id) => ({
      id,
      label: id,
      title: id,
    }));
    const edgeItems = graph.edges.map(([from, to], idx) => ({
      id: `${from}=>${to}#${idx}`,
      from,
      to,
    }));
    nodes.add(nodeItems);
    edges.add(edgeItems);

    setStatus(`${graph.nodes.length} nodes · ${graph.edges.length} edges`);

    // Focus if requested
    if (opts && opts.focusNodeId && nodes.get(opts.focusNodeId)) {
      network.focus(opts.focusNodeId, { scale: 1.4, animation: true });
      network.selectNodes([opts.focusNodeId]);
    } else {
      network.fit({ animation: true });
    }
  }

  function neighborsOf(nodeId) {
    const connected = new Set(network.getConnectedNodes(nodeId));
    connected.add(nodeId);
    return connected;
  }

  function applyHighlight(selectedId) {
    const keep = selectedId ? neighborsOf(selectedId) : null;
    const updates = [];
    nodes.forEach((n) => {
      const faded = keep ? !keep.has(n.id) : false;
      updates.push({
        id: n.id,
        color: faded
          ? { background: "rgba(148,163,184,0.18)", border: "rgba(148,163,184,0.18)" }
          : undefined,
        font: faded ? { color: "rgba(229,231,235,0.55)" } : undefined,
      });
    });
    nodes.update(updates);
  }

  network.on("click", (params) => {
    const nodeId = params.nodes && params.nodes[0];
    applyHighlight(nodeId);
    if (nodeId) setStatus(`Selected: ${nodeId}`);
    else setStatus(`${nodes.length} nodes · ${edges.length} edges`);
  });

  if (searchEl) {
    let last = "";
    searchEl.addEventListener("input", () => {
      const q = String(searchEl.value || "").trim();
      if (q === last) return;
      last = q;
      if (!q) {
        applyHighlight(null);
        network.fit({ animation: true });
        setStatus(`${nodes.length} nodes · ${edges.length} edges`);
        return;
      }
      // Find first match by substring
      const all = nodes.get();
      const hit = all.find((n) => String(n.id).toLowerCase().includes(q.toLowerCase()));
      if (hit) {
        network.focus(hit.id, { scale: 1.6, animation: true });
        network.selectNodes([hit.id]);
        applyHighlight(hit.id);
        setStatus(`Search hit: ${hit.id}`);
      } else {
        setStatus(`No match for: ${q}`);
      }
    });
  }

  window.addEventListener("message", (event) => {
    const msg = event.data;
    if (!msg || !msg.type) return;
    if (msg.type === "graph") {
      setGraph(msg.graph, msg.options || {});
      vscode.setState({ lastGraph: msg.graph, lastOptions: msg.options || {} });
    }
  });

  // Restore last state if present
  const state = vscode.getState();
  if (state?.lastGraph) {
    setGraph(state.lastGraph, state.lastOptions || {});
  }
})();

